const body = $json.body || {};

const required = ['email', 'businessName', 'websiteType'];
for (const field of required) {
  const val = body[field];
  if (!val || String(val).trim() === '') {
    throw new Error('Missing required field: ' + field);
  }
}

const clean = (v) => (v !== undefined && v !== null ? String(v).trim() : '');

const formData = {
  fullName:         clean(body.fullName),
  email:            clean(body.email).toLowerCase(),
  businessName:     clean(body.businessName),
  industry:         clean(body.industry),
  websiteType:      clean(body.websiteType),
  pagesNeeded:      Array.isArray(body.pagesNeeded)
                      ? body.pagesNeeded
                      : [body.pagesNeeded].filter(Boolean),
  designStyle:      clean(body.designStyle),
  colorPreferences: clean(body.colorPreferences),
  tone:             clean(body.tone),
  tagline:          clean(body.tagline),
  services:         clean(body.services),
  about:            clean(body.about),
  socialLinks:      clean(body.socialLinks),
  exampleSites:     clean(body.exampleSites),
  anythingElse:     clean(body.anythingElse),
  planSelected:     clean(body.planSelected),
};

const requestId = 'sr_' + Date.now() + '_' + Math.random().toString(36).slice(2, 11);

return [{ json: { formData, requestId } }];

const rawOutput = $('Call Claude API').first().json.content[0].text;
const formData  = $('Validate Input').first().json.formData;
const recordId  = $('Build Claude Prompt').first().json.recordId;
const requestId = $('Validate Input').first().json.requestId;

const files = {};

// Use matchAll to find all <!-- FILE: name --> blocks
const fileMarkerRe = /<!--\s*FILE:\s*(\S+)\s*-->([\s\S]*?)(?=<!--\s*FILE:|$)/g;
for (const m of rawOutput.matchAll(fileMarkerRe)) {
  const filename = m[1].trim();
  const content  = m[2].trim();
  if (content.length > 0) {
    files[filename] = content;
  }
}

// Fallback: raw HTML document with no FILE markers
if (Object.keys(files).length === 0) {
  const doctypeMatch = rawOutput.match(/<!DOCTYPE\s+html[\s\S]*/i);
  const htmlTagMatch = rawOutput.match(/<html[\s\S]*/i);
  const htmlContent  = doctypeMatch || htmlTagMatch;
  if (htmlContent) {
    files['index.html'] = htmlContent[0].trim();
  }
}

if (Object.keys(files).length === 0) {
  throw new Error('Could not extract any files from Claude output. Check the raw Claude response in the previous node.');
}

return [{ json: { files, formData, recordId, requestId } }];

const { files, formData, recordId, requestId } = $input.item.json;

const cfAccountId   = $env.CF_ACCOUNT_ID;
const cfApiToken    = $env.CF_API_TOKEN;
const cfProjectName = $env.CF_PROJECT_NAME;

if (!cfAccountId || !cfApiToken || !cfProjectName) {
  throw new Error('Missing Cloudflare env vars: CF_ACCOUNT_ID, CF_API_TOKEN, CF_PROJECT_NAME');
}

const boundary = '----SiteSnapBoundary' + Date.now() + Math.random().toString(36).slice(2);
const CRLF     = '\r\n';
const parts    = [];

const mimeType = (filename) => {
  if (filename.endsWith('.css'))  return 'text/css; charset=utf-8';
  if (filename.endsWith('.js'))   return 'application/javascript; charset=utf-8';
  if (filename.endsWith('.json')) return 'application/json';
  return 'text/html; charset=utf-8';
};

for (const [filename, content] of Object.entries(files)) {
  parts.push(
    '--' + boundary + CRLF +
    'Content-Disposition: form-data; name="' + filename + '"; filename="' + filename + '"' + CRLF +
    'Content-Type: ' + mimeType(filename) + CRLF +
    CRLF +
    content +
    CRLF
  );
}
parts.push('--' + boundary + '--' + CRLF);

const response = await fetch(
  'https://api.cloudflare.com/client/v4/accounts/' + cfAccountId + '/pages/projects/' + cfProjectName + '/deployments',
  {
    method:  'POST',
    headers: {
      'Authorization': 'Bearer ' + cfApiToken,
      'Content-Type':  'multipart/form-data; boundary=' + boundary,
    },
    body: parts.join(''),
  }
);

const data = await response.json();

if (!response.ok || !data.success) {
  throw new Error('Cloudflare deployment failed (' + response.status + '): ' + JSON.stringify(data.errors || data));
}

const deploymentId  = data.result.id;
const deploymentUrl = data.result.url || ('https://' + deploymentId + '.' + cfProjectName + '.pages.dev');

return [{ json: { deploymentUrl, deploymentId, formData, recordId, requestId } }];
